function storedSyncPreviewState(game=currentGame()){const states=readSyncPreviewStates();const value=states[String(game)];return value&&typeof value==='object'?value:null}
function clearStoredSyncPreviewState(game,previewId=''){const states=readSyncPreviewStates(),key=String(game||'');if(!key||!states[key])return;if(previewId&&String(states[key].preview_id||'')!==String(previewId))return;delete states[key];writeSyncPreviewStates(states)}
function syncFilterSnapshot(){const result={};for(const id of SYNC_FILTER_IDS){const element=byId(id);if(element)result[id]=element.value}return result}
function applySyncFilterSnapshot(filters){for(const[id,value]of Object.entries(filters||{})){const element=byId(id);if(!element)continue;if(element.tagName!=='SELECT'||[...element.options].some(option=>option.value===String(value)))element.value=String(value)}}
