function initializePreviewState(result,saved=null){syncState.preview=result;syncState.changes=[];syncState.total=Number(result.changes_total||0);syncState.offset=saved&&String(saved.preview_id||'')===String(result.preview_id)?Math.max(0,Number(saved.offset||0)):0;syncState.limit=saved&&String(saved.preview_id||'')===String(result.preview_id)?Math.max(1,Number(saved.limit||100)):100;syncState.expanded=new Set(saved&&String(saved.preview_id||'')===String(result.preview_id)&&Array.isArray(saved.expanded)?saved.expanded.map(String):[]);syncState.selections=new Map((result.default_selections||[]).map(row=>[String(row.change_id),{selected:row.selected!==false,action:row.action||'candidate_all',fields:Array.isArray(row.fields)?row.fields:[],reason:row.reason||''}]));if(saved&&String(saved.preview_id||'')===String(result.preview_id)){for(const[id,row]of Object.entries(saved.selections||{})){if(!row||typeof row!=='object')continue;syncState.selections.set(String(id),{selected:Boolean(row.selected),action:row.action||'candidate_all',fields:Array.isArray(row.fields)?row.fields:[],reason:row.reason||''})}applySyncFilterSnapshot(saved.filters||{});if(byId('syncPageSize'))byId('syncPageSize').value=String(syncState.limit);if(byId('syncDecisionReason'))byId('syncDecisionReason').value=String(saved.decision_reason||'')}else{applySyncFilterSnapshot({syncPageSize:String(syncState.limit)});if(byId('syncDecisionReason'))byId('syncDecisionReason').value=''}}
async function restorePreviewForGame(game=currentGame()){const token=++syncRestoreToken,saved=storedSyncPreviewState(game);let result=null;if(saved?.preview_id){try{result=await api(`/api/games/${encodeURIComponent(game)}/admin/official-achievements/preview/${encodeURIComponent(saved.preview_id)}`)}catch(error){clearStoredSyncPreviewState(game,saved.preview_id)}}if(!result){try{result=await api(`/api/games/${encodeURIComponent(game)}/admin/official-achievements/preview/active`)}catch(error){if(token!==syncRestoreToken)return;resetPreview(`已選擇 ${gameName(game)}，目前沒有可恢復的差異預覽。`,{clearStored:false});return}}if(token!==syncRestoreToken||String(currentGame())!==String(game))return;const matchingSaved=saved&&String(saved.preview_id||'')===String(result.preview_id)?saved:null;initializePreviewState(result,matchingSaved);renderMetrics(result);await loadPreviewPage();if(token!==syncRestoreToken)return;byId('adminSyncPreview').hidden=false;byId('exportSyncPreviewBtn').disabled=false;byId('adminSyncStatus').className='authMessage ok';byId('adminSyncStatus').textContent=`${gameName(game)}差異預覽已恢復；篩選、頁碼、勾選欄位與處置方式均保留，不會重新抓取來源。`;persistPreviewState()}
