 const panel=byId('adminPanelSync'); if(!panel)return;
 panel.innerHTML=`<div class="sectionCard"><h3>同步官方成就列表</h3><div class="syncGuide"><strong>新來源架構：</strong>下載已解析遊戲資料庫 → 驗證必要檔案與結構 → 解析繁體中文 → 轉換共用資料模型 → 輔助來源核對 → 產生欄位級差異 → 管理員逐項決定 → 備份、套用與完整性驗證。切換頁面、瀏覽器分頁或視窗後，差異預覽與目前操作狀態會保留；返回時直接恢復，不會重新抓取來源。</div><div class="small">目前選擇：<strong id="adminSyncGameName">—</strong></div><div id="adminSourceStatus" class="sourceCardGrid"></div><div class="adminSystemActions"><button class="secondary" id="refreshSourceStatusBtn" type="button">重新讀取來源狀態</button><button class="secondary" id="exportSyncPreviewBtn" type="button" disabled>匯出差異 JSON</button><button class="primary" id="adminSyncNowBtn" type="button">抓取並預覽差異</button></div><div class="authMessage" id="adminSyncStatus">尚未建立差異預覽。</div><div id="adminSyncPreview" hidden><div class="syncPreviewGrid" id="adminSyncMetrics"></div><div class="small" id="adminSyncPreviewNote"></div><section class="sourceDiagnostics" id="adminSourceDiagnostics"><div class="adminEmpty">建立預覽後會顯示來源診斷。</div></section><div class="syncFilterGrid"><input id="syncChangeSearch" type="search" placeholder="搜尋成就名稱或 ID"><select id="syncRiskFilter"><option value="">全部風險</option><option value="confirmed">已確認</option><option value="needs_review">待確認</option><option value="blocked">阻擋套用</option></select><select id="syncTypeFilter"><option value="">全部差異</option><option value="added">新增</option><option value="modified">修改</option><option value="removed">疑似刪除</option></select><input id="syncCategoryFilter" placeholder="分類"><input id="syncGroupFilter" placeholder="成就集／系列"><input id="syncVersionFilter" placeholder="版本"><input id="syncTagFilter" placeholder="標籤"><input id="syncRewardMin" type="number" min="0" placeholder="最低獎勵"><input id="syncRewardMax" type="number" min="0" placeholder="最高獎勵"><select id="syncHiddenFilter"><option value="">全部隱藏狀態</option><option value="true">隱藏成就</option><option value="false">非隱藏成就</option></select><input id="syncSourceFilter" placeholder="來源"><select id="syncProgressFilter"><option value="">全部進度狀態</option><option value="with">已有使用者進度</option><option value="without">沒有使用者進度</option></select><select id="syncRelationFilter"><option value="">全部關聯狀態</option><option value="with">有關聯</option><option value="without">無關聯</option><option value="stage">階段關聯</option><option value="exclusive">互斥關聯</option></select><select id="syncConflictFilter"><option value="">全部來源衝突</option><option value="with">有來源衝突</option><option value="without">無來源衝突</option></select><select id="syncChangedFieldFilter"><option value="">全部變更欄位</option><option value="name">名稱</option><option value="condition">條件</option><option value="version">版本</option><option value="category">分類</option><option value="reward">獎勵</option><option value="hidden">隱藏狀態</option><option value="tags_json">標籤</option><option value="source_order">排序</option></select><select id="syncTemplateFilter"><option value="">全部模板狀態</option><option value="only">僅模板格式差異</option><option value="exclude">排除模板格式差異</option></select><select id="syncPageSize"><option value="50">每頁 50</option><option value="100" selected>每頁 100</option><option value="200">每頁 200</option></select></div><div class="syncSelectionToolbar"><button class="secondary" id="selectSafeSyncChangesBtn" type="button">只選安全項目</button><button class="secondary" id="selectAllSyncChangesBtn" type="button">全選可處理項目</button><button class="secondary" id="selectNoSyncChangesBtn" type="button">全不選</button><span class="small" id="syncSelectedCount">已選 0 項</span></div><div class="syncChangeList" id="adminSyncChanges"></div><div class="syncPager"><button class="secondary" id="syncPrevPageBtn" type="button">上一頁</button><span class="small" id="syncPageInfo">—</span><button class="secondary" id="syncNextPageBtn" type="button">下一頁</button></div><div class="syncDecisionReason"><label for="syncDecisionReason">處置原因／備註</label><textarea id="syncDecisionReason" rows="2" placeholder="記錄採用、保留、待確認或不處置的原因；記錄性決策至少填寫 3 個字。"></textarea></div><div class="syncPreviewActions"><button class="secondary" id="adminSyncCancelBtn" type="button">取消並刪除預覽</button><button class="primary" id="adminSyncApplyBtn" type="button">建立備份並套用／記錄勾選決策</button></div></div><div class="sectionCard" style="margin-top:12px"><h3>最近同步紀錄</h3><div id="adminSyncHistory" class="syncHistory"><div class="adminEmpty">尚未載入。</div></div></div></div>`;
 byId('refreshSourceStatusBtn').onclick=loadSourceStatus;
 byId('adminSyncNowBtn').onclick=createPreview;
 byId('adminSyncApplyBtn').onclick=applyPreview;
 byId('adminSyncCancelBtn').onclick=cancelPreview;
 byId('exportSyncPreviewBtn').onclick=exportPreview;
