 byId('selectNoSyncChangesBtn').onclick=()=>selectChanges('none');
 ['syncChangeSearch','syncCategoryFilter','syncGroupFilter','syncVersionFilter','syncTagFilter','syncRewardMin','syncRewardMax','syncSourceFilter'].forEach(id=>byId(id).addEventListener('input',debounce(()=>{syncState.offset=0;persistPreviewState();loadPreviewPage()},180)));['syncRiskFilter','syncTypeFilter','syncHiddenFilter','syncProgressFilter','syncRelationFilter','syncConflictFilter','syncChangedFieldFilter','syncTemplateFilter'].forEach(id=>byId(id).addEventListener('change',()=>{syncState.offset=0;persistPreviewState();loadPreviewPage()}));
 byId('syncPageSize').onchange=()=>{syncState.limit=Number(byId('syncPageSize').value);syncState.offset=0;persistPreviewState();loadPreviewPage()};
