 byId('adminSyncChanges').addEventListener('change',event=>{if(event.target.matches('.syncChangeSelect,.syncFieldSelect,.syncDecisionAction,.syncRemoveAction')){const card=event.target.closest('.syncChangeItem');if(event.target.matches('.syncChangeSelect')){card.querySelectorAll('.syncFieldSelect').forEach(field=>{if(!field.disabled)field.checked=event.target.checked&&field.dataset.defaultSelected==='1'})}persistCardDecision(card);updateSelectionCount();persistPreviewState()}});
 byId('adminSyncChanges').addEventListener('click',handleSyncCompareClick);
 byId('syncDecisionReason').addEventListener('input',debounce(persistPreviewState,180));
 preparePanel();
