function debounce(fn,delay){let timer;return()=>{clearTimeout(timer);timer=setTimeout(fn,delay)}}
async function preparePanel(){const game=currentGame();byId('adminSyncGameName').textContent=gameName(game);await loadSourceStatus();await restorePreviewForGame(game)}
function sourceRoleText(role){return roleLabels[role]||role}
async function loadSourceStatus(){
 const game=currentGame(); byId('adminSyncGameName').textContent=gameName(game); byId('adminSourceStatus').innerHTML='<div class="adminEmpty">正在載入來源設定……</div>';
 try{
  const result=await api(`/api/games/${encodeURIComponent(game)}/admin/source-status`); syncState.status=result;
  byId('adminSourceStatus').innerHTML=(result.sources||[]).map(src=>`<article class="sourceCard"><h4>${safe(sourceRoleText(src.role))}｜${safe(src.name||src.id)}</h4><div class="sourceMeta"><span>用途：${safe(src.purpose||src.mode||'未說明')}</span><span>來源 ID：${safe(src.id||'—')}</span><span>模式：${safe(src.mode||'—')}</span><span>網址：${src.url?`<a href="${safe(src.url)}" target="_blank" rel="noopener">開啟來源</a>`:'本機來源／未設定網址'}</span></div><div class="sourceActions"><button class="secondary testSourceBtn" type="button" data-role="${safe(src.role)}">測試${safe(sourceRoleText(src.role))}</button></div></article>`).join('')||'<div class="adminEmpty">尚未設定來源。</div>';
  byId('adminSourceStatus').querySelectorAll('.testSourceBtn').forEach(btn=>btn.onclick=()=>testSource(btn));
  const history=result.history||[];
  byId('adminSyncHistory').innerHTML=history.length?history.map(row=>`<div class="syncHistoryItem" data-sync-history-id="${safe(row.id)}"><strong>${safe(row.status==='rolled_back'?'已復原':row.status||'unknown')}</strong>｜${safe(date(row.created_at))}<br><span class="small">來源 ${safe(row.source_id||'—')}｜模式 ${safe(row.source_mode||'—')}｜備份 ${safe(row.backup_name||'—')}｜結果 ${safe(JSON.stringify(row.summary||{}))}</span>${row.status==='success'&&row.post_state_hash&&row.snapshot_dir?'<div class="sourceActions"><button class="secondary rollbackSyncHistoryBtn" type="button">復原此同步</button></div>':''}</div>`).join(''):'<div class="adminEmpty">尚無同步套用紀錄。</div>';
  byId('adminSyncHistory').onclick=rollbackSyncHistory;
 }catch(error){byId('adminSourceStatus').innerHTML=`<div class="adminEmpty error">來源狀態載入失敗：${safe(error.message)}</div>`}
}
async function rollbackSyncHistory(event){const button=event.target.closest('.rollbackSyncHistoryBtn');if(!button)return;const historyId=button.closest('[data-sync-history-id]')?.dataset.syncHistoryId;if(!historyId)return;const reason=prompt('請輸入同步復原原因：','');if(reason===null)return;if(reason.trim().length<3)return alert('復原原因至少需要 3 個字。');if(!confirm('確定復原此同步嗎？只有同步範圍會回復，使用者進度與其他遊戲不受影響。'))return;button.disabled=true;try{await api(`/api/games/${encodeURIComponent(currentGame())}/admin/official-achievements/history/${encodeURIComponent(historyId)}/rollback`,{method:'POST',body:JSON.stringify({reason:reason.trim()})});await loadSourceStatus();alert('同步已安全復原。')}catch(error){button.disabled=false;alert(`同步復原失敗：${error.message}`)}}
async function testSource(button){
 const role=button.dataset.role,original=button.textContent;
 button.disabled=true;button.textContent='測試中…';
 try{
  const response=await fetch(`/api/games/${encodeURIComponent(currentGame())}/admin/source-test/${encodeURIComponent(role)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'});
  const raw=await response.text();let result={};try{result=raw?JSON.parse(raw):{}}catch{throw new Error(`伺服器回傳不是有效 JSON（HTTP ${response.status}）`)}
  if(!response.ok)throw new Error(result.detail||result.error||`HTTP ${response.status}`);
  const diagnostics=result.diagnostics||{},modeLabels={embedded_catalogue:'頁面內嵌目錄',live_index:'即時索引',live_index_with_verified_snapshot:'即時索引＋已驗證快照',live_index_with_detail_resolution:'即時索引＋新成就詳細頁'};
  const lines=[`${sourceRoleText(role)}測試${result.ok?'成功':'失敗'}`,`HTTP：${result.http_status??response.status??'—'}`,`耗時：${result.elapsed_ms} ms`];
  if(diagnostics.verification_mode)lines.push(`驗證方式：${modeLabels[diagnostics.verification_mode]||diagnostics.verification_mode}`);
  if(diagnostics.parsed_count!==undefined)lines.push(`來源成就總數：${diagnostics.parsed_count} 筆`);
  if(diagnostics.resolved_row_count!==undefined&&Number(diagnostics.resolved_row_count)>0)lines.push(`本次解析詳細資料：${diagnostics.resolved_row_count} 筆`);
  if(diagnostics.selected_channel_id)lines.push(`成就頻道：${diagnostics.selected_channel_id}`);
  if(diagnostics.test_observation_count)lines.push(`測試觀察：${diagnostics.test_observation_count} 筆`);
  if(result.error)lines.push(`錯誤：${result.error}`);
  alert(lines.join('\n'));
 }catch(error){alert(`來源測試失敗：${error.message}`)}finally{button.disabled=false;button.textContent=original}
}
function resetPreview(message='',{clearStored=true}={}){const previous=syncState.preview;if(clearStored&&previous)clearStoredSyncPreviewState(previous.game_id,previous.preview_id);syncState.preview=null;syncState.changes=[];syncState.offset=0;syncState.total=0;syncState.selections=new Map();syncState.expanded=new Set();byId('adminSyncPreview').hidden=true;byId('exportSyncPreviewBtn').disabled=true;if(message){byId('adminSyncStatus').className='authMessage';byId('adminSyncStatus').textContent=message}}

function previewOutcomeCounts(result){const s=result?.summary||{};return{total:Number(s.total_changes??(Number(s.added||0)+Number(s.modified||0)+Number(s.removed||0))),safe:Number(s.safe_default||0),review:Number(s.needs_review||0),blocked:Number(s.blocked||0),unchanged:Number(s.unchanged||0)}}
function previewOutcomeMessage(result,game){const c=previewOutcomeCounts(result),name=gameName(game),meta=result?.metadata||{},cv=meta.cross_validation||{};if(meta.apply_blocked||cv.source_complete===false){const parsed=Number(cv.primary_parsed_count||result.candidate_count||0),reported=Number(cv.source_reported_count||cv.official_observations||0),missing=Number(cv.missing_source_row_count||Math.max(0,reported-parsed));return`${name}來源資料不完整：主要來源只解析出 ${parsed} 項，來源總數為 ${reported} 項，仍缺少 ${missing} 項完整內容。本次只建立診斷預覽，不能判定資料一致，也不能正式套用。`;}if(c.total===0)return`${name}資料檢查完成，目前資料與來源一致，沒有需要更新的項目。`;if(c.safe===0)return`${name}差異預覽已建立。這次發現 ${c.total} 項差異，但沒有可直接安全套用的項目，請查看下方的「待確認」或「已阻擋」內容並逐項決定。`;return`${name}差異預覽已建立。本次有 ${c.safe} 項可安全更新，系統已預先選取；另有 ${c.review} 項需要人工確認、${c.blocked} 項因安全規則暫時阻擋。`}
