function valueText(value){if(value===null||value===undefined||value==='')return '（空白）';if(typeof value==='object')return JSON.stringify(value);return String(value)}
function selectChanges(mode){byId('adminSyncChanges').querySelectorAll('.syncChangeItem').forEach(card=>{const input=card.querySelector('.syncChangeSelect');if(input.disabled)return;input.checked=mode==='all'||(mode==='safe'&&card.classList.contains('confirmed'));card.querySelectorAll('.syncFieldSelect').forEach(field=>{if(!field.disabled)field.checked=input.checked&&field.dataset.defaultSelected==='1'});persistCardDecision(card)});updateSelectionCount();persistPreviewState()}
function updateSelectionCount(){const selected=[...syncState.selections.values()].filter(row=>row.selected).length,blocked=Boolean(syncState.preview?.metadata?.apply_blocked||syncState.preview?.metadata?.diagnostic_preview);byId('syncSelectedCount').textContent=blocked?'此預覽因來源內容不完整，只供診斷，不能正式套用。':`此預覽已選 ${selected} 項（可跨頁保留）；只有已勾選項目會送出。`;byId('adminSyncApplyBtn').disabled=blocked||!selected}
function collectDecisions(){byId('adminSyncChanges').querySelectorAll('.syncChangeItem').forEach(persistCardDecision);const selected=[],decisions={};for(const[id,decision]of syncState.selections){if(!decision.selected)continue;selected.push(id);decisions[id]={action:decision.action||'candidate_all',fields:Array.isArray(decision.fields)?decision.fields:[],reason:decision.reason||''}}return{selected,decisions}}
async function applyPreview(){if(!syncState.preview)return;const{selected,decisions}=collectDecisions();if(!selected.length)return alert('請至少勾選一項差異或記錄性決策。');const reason=byId('syncDecisionReason')?.value.trim()||'';const recordActions=new Set(['keep','record_no_action','pending_review','legal_difference']);if(Object.values(decisions).some(row=>recordActions.has(row.action))&&reason.length<3)return alert('記錄不處置、保留、待確認或合法差異時，請填寫至少 3 個字的處置原因。');for(const row of Object.values(decisions))if(!row.reason)row.reason=reason;const invalid=Object.entries(decisions).filter(([,row])=>['candidate','admin_override'].includes(row.action)&&!row.fields.length);if(invalid.length)return alert(`有 ${invalid.length} 項選擇「使用已勾選欄位」，但沒有勾選任何欄位。請勾選欄位、改用「使用來源全部欄位」，或改成記錄性處置。`);const review=syncState.changes.filter(row=>selected.includes(row.change_id)&&row.risk!=='confirmed').length;if(!confirm(`準備處理 ${selected.length} 項差異，其中 ${review} 項需要人工確認。\n系統會先建立資料庫備份，再逐欄套用／記錄決策並讀回驗證。確定繼續嗎？`))return;const button=byId('adminSyncApplyBtn');button.disabled=true;byId('adminSyncStatus').textContent='正在建立備份、套用或記錄決策，並逐欄驗證 JSON 與 SQLite……';try{const result=await api(`/api/games/${encodeURIComponent(syncState.preview.game_id)}/admin/official-achievements/apply`,{method:'POST',body:JSON.stringify({preview_id:syncState.preview.preview_id,selected_change_ids:selected,decisions,reason})});const summary=result.summary||{},verify=summary.verification||{};byId('adminSyncStatus').className='authMessage ok';byId('adminSyncStatus').textContent=`處理完成：新增 ${summary.added||0}、實際修改 ${summary.modified||0}、刪除 ${summary.removed||0}、記錄不變更 ${summary.recorded_no_action||0}、待確認 ${summary.pending_review||0}、合法差異 ${summary.legal_difference||0}、管理員覆寫 ${summary.admin_overrides_written||0}；逐欄驗證 ${verify.checked_fields||0} 欄，備份 ${result.backup||'已建立'}。`;resetPreview();await loadSourceStatus();if(typeof loadAdminGameCatalog==='function')await loadAdminGameCatalog(result.game_id);if(typeof renderAdminAchievements==='function')renderAdminAchievements()}catch(error){byId('adminSyncStatus').className='authMessage error';byId('adminSyncStatus').textContent=`套用失敗：${error.message}`;button.disabled=false}}
async function cancelPreview(){if(!syncState.preview)return resetPreview('沒有可取消的預覽。');if(!confirm('確定刪除此差異預覽嗎？正式資料不會變更。'))return;try{await api(`/api/games/${encodeURIComponent(syncState.preview.game_id)}/admin/official-achievements/preview/${encodeURIComponent(syncState.preview.preview_id)}`,{method:'DELETE',body:'{}'});resetPreview('預覽已取消並刪除，正式資料未變更。');await loadSourceStatus()}catch(error){alert(`取消失敗：${error.message}`)}}
function exportPreview(){if(!syncState.preview)return;const blob=new Blob([JSON.stringify(syncState.preview,null,2)],{type:'application/json;charset=utf-8'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`sync-preview-${syncState.preview.game_id}-${syncState.preview.preview_id}.json`;a.click();URL.revokeObjectURL(url)}
function replaceValidationDialog(){const dialog=byId('validationDialog');if(!dialog)return;dialog.innerHTML=`<div class="dialogHead"><div><h2>成就重複與異常處置</h2><div class="small">掃描結果不會自動修改資料；只有勾選並確認的處置才會執行。</div></div><button class="secondary" id="closeValidationBtn" type="button">關閉</button></div><div class="dialogBody"><div id="validationSummary" class="adminSummary"></div><div class="validationToolbar"><input id="issueSearch" type="search" placeholder="搜尋問題、成就或 ID"><select id="issueRiskFilter"><option value="">全部風險</option><option value="blocked">阻擋</option><option value="needs_review">待確認</option><option value="confirmed">安全</option></select><select id="issueKindFilter"><option value="">全部類型</option></select></div><div class="adminSystemActions"><button class="secondary" id="selectSafeIssuesBtn" type="button">選取可安全處置項目</button><button class="secondary" id="clearIssueSelectionBtn" type="button">取消全部選取</button></div><div id="validationList" class="stack" style="margin-top:12px"></div><div class="sectionCard" style="margin-top:12px"><label>本次處置原因<input id="catalogRepairReason" maxlength="1000" placeholder="例如：合併確認為同一成就的重複資料" required></label><div class="small" id="repairImpactSummary">尚未選擇處置。</div><div class="adminFormActions"><button class="primary" id="applyCatalogRepairsBtn" type="button" disabled>預覽影響並執行處置</button></div></div></div>`;byId('closeValidationBtn').onclick=()=>dialog.close();['issueSearch','issueRiskFilter','issueKindFilter'].forEach(id=>byId(id).addEventListener(id==='issueSearch'?'input':'change',renderIssues));byId('validationList').addEventListener('change',updateRepairSummary);byId('selectSafeIssuesBtn').onclick=()=>selectIssues(true);byId('clearIssueSelectionBtn').onclick=()=>selectIssues(false);byId('applyCatalogRepairsBtn').onclick=applyCatalogRepairs}
async function runHealthScan(items=adminGameData){const result=await api(`/api/games/${encodeURIComponent(currentGame())}/admin/catalog/validate`,{method:'POST',body:JSON.stringify({items})});scanState={result,items};const kinds=Object.keys(result.by_kind||{});byId('issueKindFilter').innerHTML='<option value="">全部類型</option>'+kinds.map(k=>`<option value="${safe(k)}">${safe(k)}（${result.by_kind[k]}）</option>`).join('');byId('validationSummary').textContent=`${gameName()}｜掃描 ${result.count} 項；錯誤 ${result.errors}、警告 ${result.warnings}、提示 ${result.info}；阻擋 ${result.by_risk?.blocked||0}、待確認 ${result.by_risk?.needs_review||0}；已由管理員處置並隱藏 ${result.resolved_count||0} 項。`;renderIssues();const dialog=byId('validationDialog');if(!dialog.open)dialog.showModal();return result}
function filteredIssues(){const q=byId('issueSearch').value.trim().toLowerCase(),risk=byId('issueRiskFilter').value,kind=byId('issueKindFilter').value;return(scanState.result?.issues||[]).filter(i=>(!risk||i.risk===risk)&&(!kind||i.kind===kind)&&(!q||`${i.message} ${i.name||''} ${i.achievement_id||''} ${(i.related_ids||[]).join(' ')}`.toLowerCase().includes(q)))}
function renderIssues(){const issues=filteredIssues();byId('validationList').innerHTML=issues.length?issues.map(issue=>{const actions=issue.actions||['keep'];return `<article class="issueCard ${safe(issue.risk||'needs_review')}" data-issue-id="${safe(issue.issue_id)}"><div class="issueHead"><input class="issueSelect" type="checkbox"><strong>${safe(issue.name||issue.achievement_id||issue.kind)}</strong><span class="statusBadge ${issue.risk==='blocked'?'disabled':'pending'}">${safe(riskLabels[issue.risk]||issue.risk)}</span><span class="small">${safe(issue.kind)}</span></div><p>${safe(issue.message)}</p><div class="small">主要 ID：${safe(issue.achievement_id||'—')}｜關聯 ID：${safe((issue.related_ids||[]).join('、')||'—')}｜影響進度 ${Number(issue.progress_count||0)}｜影響關聯 ${Number(issue.relation_count||0)}</div><div class="issueActionGrid"><span class="small">處置方式</span><select class="issueAction">${actions.map(a=>`<option value="${safe(a)}">${safe(actionLabels[a]||a)}</option>`).join('')}</select><input class="issueKeepId" placeholder="保留／正式 ID" value="${safe(issue.achievement_id||'')}"><div class="issueExtra"><input class="issueGroupId" placeholder="關聯群組 ID（建立關聯時使用）"><input class="issueAliasId" placeholder="舊 ID／別名 ID"><textarea class="issueManualChanges compactText" placeholder='手動修改 JSON，例如 {"version":"1.1"}'></textarea></div></div></article>`}).join(''):'<div class="adminEmpty">此篩選條件沒有異常。</div>';updateRepairSummary()}
function selectIssues(safeOnly){byId('validationList').querySelectorAll('.issueCard').forEach(card=>{const issue=(scanState.result?.issues||[]).find(i=>i.issue_id===card.dataset.issueId),box=card.querySelector('.issueSelect');box.checked=!safeOnly?false:Boolean(issue&&issue.risk!=='blocked'&&['duplicate_order','missing_version','missing_category'].includes(issue.kind));});updateRepairSummary()}
function updateRepairSummary(){const cards=[...byId('validationList').querySelectorAll('.issueCard')].filter(card=>card.querySelector('.issueSelect').checked),progress=cards.reduce((n,card)=>n+Number((scanState.result?.issues||[]).find(i=>i.issue_id===card.dataset.issueId)?.progress_count||0),0),relations=cards.reduce((n,card)=>n+Number((scanState.result?.issues||[]).find(i=>i.issue_id===card.dataset.issueId)?.relation_count||0),0);byId('repairImpactSummary').textContent=`已選 ${cards.length} 項；可能影響 ${progress} 筆使用者進度與 ${relations} 個關聯引用。執行前會建立備份，失敗時自動回復。`;byId('applyCatalogRepairsBtn').disabled=!cards.length}
async function applyCatalogRepairs(){const reason=byId('catalogRepairReason').value.trim();if(reason.length<3)return alert('請填寫至少 3 個字的處置原因。');const actions={};for(const card of byId('validationList').querySelectorAll('.issueCard')){if(!card.querySelector('.issueSelect').checked)continue;const action=card.querySelector('.issueAction').value,decision={action,keep_id:card.querySelector('.issueKeepId').value.trim(),group_id:card.querySelector('.issueGroupId').value.trim(),alias_id:card.querySelector('.issueAliasId').value.trim()};if(action==='manual_edit'){try{decision.changes=JSON.parse(card.querySelector('.issueManualChanges').value||'{}')}catch{return alert('手動修改 JSON 格式錯誤。')}}actions[card.dataset.issueId]=decision}const count=Object.keys(actions).length;if(!confirm(`準備處置 ${count} 項異常。系統會先建立資料庫備份、執行變更、驗證完整性；失敗時自動回復。確定繼續嗎？`))return;const button=byId('applyCatalogRepairsBtn');button.disabled=true;try{const result=await api(`/api/games/${encodeURIComponent(currentGame())}/admin/catalog/repair`,{method:'POST',body:JSON.stringify({scan_id:scanState.result.scan_id,actions,reason})});if(typeof loadAdminGameCatalog==='function')await loadAdminGameCatalog(currentGame());if(typeof renderAdminAchievements==='function')renderAdminAchievements();byId('catalogRepairReason').value='';await runHealthScan([]);alert(`處置完成。\n已實際變更／記錄：${result.changed_count}\n明確選擇不變更：${result.no_change_count}\n剩餘異常：${result.remaining_issues}\n成就數：${result.count}\n備份：${result.backup}`)}catch(error){alert(`處置失敗：${error.message}`)}finally{button.disabled=false}}
