function auditHumanIdentifier(value,labels={},fallback='其他資料'){const raw=String(value||'').trim();if(!raw)return'—';if(labels[raw])return labels[raw];const parts=raw.split(/[_\-\s]+/).filter(Boolean),translated=parts.map(part=>auditWordLabels[part.toLowerCase()]||'');return translated.every(Boolean)?translated.join(''):fallback}
function auditActionText(action){const raw=String(action||'').trim();if(auditActionLabels[raw])return auditActionLabels[raw];if(typeof adminActionLabel==='function'){const translated=adminActionLabel(raw);if(translated&&translated!==raw&&translated!=='其他管理操作')return translated}return auditHumanIdentifier(raw,{},'其他管理操作')}
function auditCategoryText(value){return auditHumanIdentifier(value,auditCategoryLabels,'其他管理分類')}
function auditStatusText(value){return auditHumanIdentifier(value,auditStatusLabels,'其他結果')}
function auditGameText(value){if(typeof adminLogGameName==='function')return adminLogGameName(value)||'—';return auditHumanIdentifier(value,{wuwa:'鳴潮',hsr:'崩壞：星穹鐵道',genshin:'原神',zzz:'絕區零'})}
function auditTargetTypeText(value){return auditHumanIdentifier(value,auditTargetLabels,'操作目標')}
function auditFieldText(value){return auditHumanIdentifier(value,auditFieldLabels,'其他資料')}
function auditSummaryTextValue(log){return String(log?.summary||'').trim()||auditActionText(log?.action)}
function auditIdentifierKey(key=''){const raw=String(key||'').toLowerCase();return raw==='id'||raw==='uuid'||raw==='event_id'||raw==='request_id'||raw==='target_id'||raw==='user_id'||raw==='actor_user_id'||raw==='target_user_id'||raw==='batch_id'||raw==='preview_id'||raw==='scan_id'||raw==='issue_id'||raw==='category_id'||raw==='achievement_id'||raw.endsWith('_uuid')||(raw.endsWith('_id')&&raw!=='game_id')}
function auditTechnicalKey(key=''){const raw=String(key||'').toLowerCase();return auditIdentifierKey(raw)||raw.startsWith('_')||raw.endsWith('_hash')||raw.endsWith('_json')||raw.endsWith('_by')||raw.includes('checksum')||new Set(['pipeline_version','current_fingerprint','state_component_hashes','file_manifest','parser_diagnostics','secondary_diagnostics','diagnostics','cache_file','source_ref','source_page','source_mode','source_policy','primary_source','secondary_source','fallback_source','cross_validation','primary_fields_authoritative','secondary_overwrite_allowed','local_game_files_used','guide_data_used','identity_bridge','rules_version','options','confirmation_text']).has(raw)}
function auditIdentifierValue(value){const raw=String(value??'').trim();return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(raw)||/^[0-9a-f]{24,}$/i.test(raw)}
function auditScalarText(value,key=''){if(value===undefined||value===null||value==='')return'未記錄';if(auditIdentifierKey(key)||auditIdentifierValue(value))return'已由系統記錄';if(typeof value==='boolean')return value?'是':'否';if(typeof value==='number')return Number.isFinite(value)?String(value):'未記錄';const raw=String(value),lower=raw.toLowerCase();if(key==='game_id'||key==='game_name'||key==='game')return auditGameText(raw);if(key==='status'||key.endsWith('_status'))return auditStatusText(raw);if(['true','false'].includes(lower))return lower==='true'?'是':'否';if(auditStatusLabels[lower])return auditStatusLabels[lower];return raw}
function auditValueSummary(value,key=''){if(Array.isArray(value))return value.length?`共 ${value.length} 項`:'沒有項目';if(value&&typeof value==='object'){if(value._truncated)return'內容較長，系統已完整保存';if(value._parse_error)return'舊紀錄格式無法轉成易讀內容';const keys=auditVisibleEntries(value);return keys.length?`共 ${keys.length} 個欄位`:'沒有可顯示的內容'}return auditScalarText(value,key)}
function auditVisibleEntries(value){return Object.entries(value||{}).filter(([key,childValue])=>(!auditTechnicalKey(key))||(Array.isArray(childValue)&&String(key).toLowerCase().endsWith('_ids')))}
function auditValueMarkup(value,key='',depth=0){if(Array.isArray(value)){if(!value.length)return'<span class="auditEmptyValue">沒有項目</span>';const label=key==='category_ids'?'個分類':key==='server_ids'?'個服務器':key==='achievement_ids'?'個成就':'項';return `<span>共 ${value.length} ${label}</span>`}if(value&&typeof value==='object'){if(value._truncated)return'<div class="auditTruncatedValue"><strong>內容較長，系統已完整保存</strong></div>';if(value._parse_error)return'<div class="auditErrorValue"><strong>舊紀錄格式無法轉成易讀內容</strong></div>';const entries=auditVisibleEntries(value);if(!entries.length)return'<span class="auditEmptyValue">沒有可顯示的內容</span>';return `<div class="auditObjectRows">${entries.map(([childKey,childValue])=>`<div class="auditObjectRow"><span>${safe(auditFieldText(childKey))}</span><div>${depth>=2?safe(auditValueSummary(childValue,childKey)):auditValueMarkup(childValue,childKey,depth+1)}</div></div>`).join('')}</div>`}return`<span>${safe(auditScalarText(value,key))}</span>`}
function auditValuesEqual(left,right){try{return JSON.stringify(left)===JSON.stringify(right)}catch{return left===right}}
function auditHasValue(value){return !(value===undefined||value===null||value===''||(Array.isArray(value)&&!value.length)||(value&&typeof value==='object'&&!Object.keys(value).length))}
function auditDiffMarkup(before,after){if(!auditHasValue(before)&&!auditHasValue(after))return'<div class="auditEmptyValue">這筆操作沒有保存可顯示的欄位差異。</div>';const left=before&&typeof before==='object'&&!Array.isArray(before)?before:{內容:before},right=after&&typeof after==='object'&&!Array.isArray(after)?after:{內容:after},keys=[...new Set([...Object.keys(left||{}),...Object.keys(right||{})])].filter(key=>!auditTechnicalKey(key)||(Array.isArray(left?.[key]||right?.[key])&&String(key).toLowerCase().endsWith('_ids')));if(!keys.length)return'<div class="auditEmptyValue">這筆操作只有系統識別資料，畫面不顯示。</div>';return `<div class="auditDiffTable"><div class="auditDiffHead"><span>欄位</span><span>變更前</span><span>變更後</span></div>${keys.map(key=>`<div class="auditDiffRow ${auditValuesEqual(left?.[key],right?.[key])?'same':'changed'}"><strong>${safe(auditFieldText(key))}</strong><div>${auditValueMarkup(left?.[key],key)}</div><div>${auditValueMarkup(right?.[key],key)}</div></div>`).join('')}</div>`}
function auditMetadataMarkup(value){if(!auditHasValue(value))return'<div class="auditEmptyValue">沒有附加資訊。</div>';return auditValueMarkup(value,'metadata')}
function auditTargetTextValue(log){const type=auditTargetTypeText(log?.target_type);return log?.target_email?`${type}：${log.target_email}`:type}
function auditReadableValue(value,key='',indent='  '){if(Array.isArray(value))return value.length?`共 ${value.length} 項`:'沒有項目';if(value&&typeof value==='object')return auditVisibleEntries(value).map(([childKey,childValue])=>`${auditFieldText(childKey)}：${auditValueSummary(childValue,childKey)}`).join('\n')||'沒有可顯示的內容';return auditScalarText(value,key)}
function auditDetailText(log){return [`操作時間：${date(log.created_at)}`,`操作事件：${auditActionText(log.action)}`,`執行結果：${auditStatusText(log.status)}`,`管理員：${log.actor_email||'已刪除帳號'}`,`遊戲：${auditGameText(log.game_id)}`,`分類：${auditCategoryText(log.category)}`,`操作目標：${auditTargetTextValue(log)}`,`操作說明：${auditSummaryTextValue(log)}`,`錯誤內容：${log.error_message||'無'}`,`備份檔案：${log.backup_name||'無'}`,'','變更前：',auditReadableValue(log.before),'','變更後：',auditReadableValue(log.after),'','附加資訊：',auditReadableValue(log.metadata)].join('\n')}
function renderAuditRecords(){byId('auditSummary').textContent=`共 ${auditState.total} 筆符合紀錄；目前沒有自動到期或清除期限，封存只會從預設列表隱藏，不會刪除資料。`;byId('adminLogsBody').innerHTML=auditState.logs.length?auditState.logs.map(log=>`<tr><td data-label="時間">${safe(date(log.created_at))}</td><td data-label="事件"><strong>${safe(auditActionText(log.action))}</strong></td><td data-label="管理員">${safe(log.actor_email||'已刪除帳號')}</td><td data-label="分類／結果">${safe(auditCategoryText(log.category))}<div class="small">${safe(auditStatusText(log.status))}</div></td><td data-label="遊戲／目標">${safe(auditGameText(log.game_id))}<div class="small">${safe(auditTargetTextValue(log))}</div></td><td data-label="摘要">${safe(auditSummaryTextValue(log))}</td><td data-label="操作"><div class="auditActionButtons"><button class="secondary viewAuditBtn" data-id="${log.id}">詳細</button>${log.locked?'<span class="auditLockedState">已鎖定</span>':`<button class="secondary archiveAuditBtn" data-id="${log.id}">封存</button>`}</div></td></tr>`).join(''):'<tr><td colspan="7" class="adminEmpty">沒有符合條件的紀錄。</td></tr>';const first=auditState.total?auditState.offset+1:0,last=Math.min(auditState.offset+auditState.limit,auditState.total);byId('auditPageInfo').textContent=`${first}–${last} / ${auditState.total}`;byId('auditPrevBtn').disabled=auditState.offset<=0;byId('auditNextBtn').disabled=auditState.offset+auditState.limit>=auditState.total}
function openAuditDetailDialog(log){if(!log)return;const dialog=byId('auditDetailDialog'),content=byId('auditDetailContent'),subtitle=byId('auditDetailSubtitle');if(!dialog||!content)return;activeAuditDetailText=auditDetailText(log);if(subtitle)subtitle.textContent=`${auditActionText(log.action)}｜${auditStatusText(log.status)}｜${date(log.created_at)}`;const rows=[['操作時間',date(log.created_at)],['管理員',log.actor_email||'已刪除帳號'],['遊戲',auditGameText(log.game_id)],['分類',auditCategoryText(log.category)],['執行結果',auditStatusText(log.status)],['操作目標',auditTargetTextValue(log)],['備份檔案',log.backup_name||'無']];content.innerHTML=`<div class="auditReadableDetail"><section class="auditDetailCard"><h4>基本資訊</h4>${rows.map(([key,value])=>`<div class="auditDetailRow"><span>${safe(key)}</span><span>${safe(value)}</span></div>`).join('')}</section><section class="auditDetailCard auditSummaryCard"><h4>操作說明</h4><p>${safe(auditSummaryTextValue(log))}</p>${log.error_message?`<div class="auditErrorMessage"><strong>錯誤內容</strong><span>${safe(log.error_message)}</span></div>`:''}</section><section class="auditDetailCard auditDetailFull"><h4>欄位變更</h4>${auditDiffMarkup(log.before,log.after)}</section><section class="auditDetailCard auditDetailFull"><h4>附加資訊</h4>${auditMetadataMarkup(log.metadata)}</section></div>`;if(dialog.open)dialog.close();dialog.showModal()}
function bindAuditDetailDialog(){const dialog=byId('auditDetailDialog'),close=byId('closeAuditDetailBtn'),copy=byId('copyAuditDetailBtn');if(!dialog||dialog.dataset.bound==='1')return;dialog.dataset.bound='1';if(close)close.onclick=()=>dialog.close();if(copy)copy.onclick=async()=>{try{if(navigator.clipboard?.writeText)await navigator.clipboard.writeText(activeAuditDetailText);else{const area=document.createElement('textarea');area.value=activeAuditDetailText;document.body.appendChild(area);area.select();document.execCommand('copy');area.remove()}const old=copy.textContent;copy.textContent='已複製';setTimeout(()=>copy.textContent=old,1200)}catch(error){alert(`複製失敗：${error.message}`)}};dialog.addEventListener('click',event=>{if(event.target!==dialog)return;const rect=dialog.getBoundingClientRect();if(event.clientX<rect.left||event.clientX>rect.right||event.clientY<rect.top||event.clientY>rect.bottom)dialog.close()})}
async function handleAuditAction(event){const view=event.target.closest('.viewAuditBtn'),archive=event.target.closest('.archiveAuditBtn');if(view){openAuditDetailDialog(auditState.logs.find(row=>String(row.id)===view.dataset.id));return}if(archive){const reason=prompt('請輸入封存原因（至少 3 個字）：');if(!reason||reason.trim().length<3)return;try{await api(`/api/admin/audit-logs/${encodeURIComponent(archive.dataset.id)}/archive`,{method:'POST',body:JSON.stringify({reason:reason.trim()})});await loadAuditRecords()}catch(error){alert(error.message)}}}
